// ── Helpers ──
function canonicalPair(a, b) {
  return a < b ? [a, b] : [b, a];
}

function futureDate(daysFromNow, hour) {
  const d = new Date();
  d.setDate(d.getDate() + daysFromNow);
  d.setHours(hour, 0, 0, 0);
  return d;
}

function pastDate(daysAgo, hour) {
  const d = new Date();
  d.setDate(d.getDate() - daysAgo);
  d.setHours(hour, 0, 0, 0);
  return d;
}

async function main() {
  console.log('🦷 Dentara Production Seed — Starting...\n');

  const hash = await bcrypt.hash(PASSWORD, 12);
  console.log('✅ Password hashed');

  // ── Create Students ──
  const studentIds = [];
  for (const s of STUDENTS) {
    const cases = Object.entries(s.quotas).map(([name, count]) => ({ name, count }));
    const user = await prisma.user.upsert({
      where: { email: s.email },
      update: {
        password: hash, fullName: s.fullName, name: s.fullName, role: 'student',
        username: s.username, school: s.school, yearLevel: s.yearLevel, studentId: s.studentId,
        clinicAddress: s.clinicAddress, casesJson: JSON.stringify(cases),
        availabilityJson: JSON.stringify(s.availability),
      },
      create: {
        email: s.email, password: hash, fullName: s.fullName, name: s.fullName, role: 'student',
        username: s.username, school: s.school, yearLevel: s.yearLevel, studentId: s.studentId,
        clinicAddress: s.clinicAddress, casesJson: JSON.stringify(cases),
        availabilityJson: JSON.stringify(s.availability),
      },
    });
    studentIds.push(user.id);
  }
  console.log(`✅ ${studentIds.length} student accounts seeded`);

  // ── Create Patients ──
  const patientIds = [];
  for (const p of PATIENTS) {
    const user = await prisma.user.upsert({
      where: { email: p.email },
      update: {
        password: hash, fullName: p.fullName, name: p.fullName, role: 'patient',
        age: p.age, phone: p.phone, concern: p.concern, location: p.location,
      },
      create: {
        email: p.email, password: hash, fullName: p.fullName, name: p.fullName, role: 'patient',
        age: p.age, phone: p.phone, concern: p.concern, location: p.location,
      },
    });
    patientIds.push(user.id);
  }
  console.log(`✅ ${patientIds.length} patient accounts seeded`);

  // ── Create Universities ──
  for (const u of UNIVERSITIES) {
    await prisma.user.upsert({
      where: { email: u.email },
      update: {
        password: hash, fullName: u.fullName, name: u.fullName, role: 'university',
        school: u.school, clinicAddress: u.clinicAddress,
      },
      create: {
        email: u.email, password: hash, fullName: u.fullName, name: u.fullName, role: 'university',
        school: u.school, clinicAddress: u.clinicAddress,
      },
    });
  }
  console.log(`✅ ${UNIVERSITIES.length} university account seeded`);

  // ── Create Bookings + Notifications ──
  const bookingConfigs = [
    { sIdx: 0, pIdx: 0, status: 'CONFIRMED', days: 3,   hour: 9,  case: 'Tooth Removal',    notes: 'Impacted lower right wisdom tooth extraction',     notif: 'ACCEPTED' },
    { sIdx: 1, pIdx: 1, status: 'CONFIRMED', days: 5,   hour: 14, case: 'Tooth Filling',     notes: 'Composite filling on tooth #36 and #46',            notif: 'ACCEPTED' },
    { sIdx: 2, pIdx: 4, status: 'CONFIRMED', days: 7,   hour: 10, case: 'Root Canal',        notes: 'Root canal treatment on severely decayed molar',    notif: 'ACCEPTED' },
    { sIdx: 3, pIdx: 3, status: 'PENDING',   days: 10,  hour: 9,  case: 'Gum Care',          notes: 'Deep scaling and root planing requested',           notif: 'BOOKING_REQUEST' },
    { sIdx: 4, pIdx: 5, status: 'PENDING',   days: 12,  hour: 14, case: 'Tooth Filling',     notes: 'Anterior composite restoration for chipped tooth',  notif: 'OFFER' },
    { sIdx: 5, pIdx: 6, status: 'PENDING',   days: 14,  hour: 10, case: 'Gum Care',          notes: 'Periodontal assessment and prophylaxis',            notif: 'BOOKING_REQUEST' },
    { sIdx: 6, pIdx: 2, status: 'CANCELLED', days: -5,  hour: 11, case: 'Tooth Replacement', notes: 'Patient rescheduled — prosthetic work deferred',     notif: 'REJECTED' },
    { sIdx: 7, pIdx: 7, status: 'CANCELLED', days: -3,  hour: 15, case: 'Tooth Removal',     notes: 'Student unavailable for wisdom tooth extraction',   notif: 'REJECTED' },
  ];

  for (const bc of bookingConfigs) {
    const studentId = studentIds[bc.sIdx];
    const patientId = patientIds[bc.pIdx];
    const scheduledAt = bc.days >= 0 ? futureDate(bc.days, bc.hour) : pastDate(-bc.days, bc.hour);

    const booking = await prisma.booking.create({
      data: { studentId, patientId, scheduledAt, status: bc.status, caseLabel: bc.case, notes: bc.notes },
    });

    // Notification receiver/sender depends on event type
    const isOffer = bc.notif === 'OFFER';
    const isRequest = bc.notif === 'BOOKING_REQUEST';
    await prisma.notification.create({
      data: {
        userId:      isOffer ? patientId : (isRequest ? studentId : patientId),
        senderId:    isOffer ? studentId : (isRequest ? patientId : studentId),
        type:        bc.notif,
        status:      bc.status === 'PENDING' ? 'UNREAD' : 'READ',
        referenceId: booking.id,
      },
    });
  }
  console.log(`✅ ${bookingConfigs.length} bookings + notifications created`);

  // ── Create Conversations & Messages ──
  const chatPairs = [
    { sIdx: 0, pIdx: 0, messages: [
      { fromStudent: true,  content: 'Hi Roberto! I reviewed your case — the impacted wisdom tooth looks like it needs surgical extraction. I have experience with these.' },
      { fromStudent: false, content: 'Salamat po, Doc! Masakit na talaga. When is the earliest available slot?' },
      { fromStudent: true,  content: 'I have openings this Monday at 9 AM and Wednesday at 2 PM. The procedure usually takes about 45 minutes.' },
      { fromStudent: false, content: 'Monday 9 AM works for me. Thank you so much, looking forward to it!' },
    ]},
    { sIdx: 1, pIdx: 1, messages: [
      { fromStudent: false, content: 'Hello Doc Maria! I saw your profile and you specialize in fillings. I have several cavities that need attention.' },
      { fromStudent: true,  content: 'Hi Elena! Yes, composite restorations are my focus area. How many teeth are affected?' },
      { fromStudent: false, content: 'My dentist said around 3-4 teeth on the lower left and right. Will it be painful?' },
      { fromStudent: true,  content: "Don't worry, we use local anesthesia so you'll be comfortable throughout. Let's schedule your first visit this week!" },
    ]},
    { sIdx: 2, pIdx: 4, messages: [
      { fromStudent: true,  content: "Good morning, Mr. Morales. I'm Dr. Carlos from UE Dentistry. I'd like to help with your root canal case." },
      { fromStudent: false, content: "Good morning Doc. I've been putting this off for months. The pain comes and goes." },
      { fromStudent: true,  content: "That's common with pulp inflammation. The sooner we treat it, the better chance of saving the tooth. I have slots on Thursday." },
    ]},
    { sIdx: 3, pIdx: 3, messages: [
      { fromStudent: false, content: 'Hi Doc Patricia, I noticed my gums have been bleeding a lot lately, especially when I brush. Can you help?' },
      { fromStudent: true,  content: 'Hello Carmen! Bleeding gums can indicate gingivitis or early periodontal disease. I recommend we do a full periodontal assessment first.' },
      { fromStudent: false, content: "That sounds good. I'm available most weekday mornings. What do I need to prepare?" },
      { fromStudent: true,  content: "Just come with clean teeth and avoid eating 2 hours before. I'll take some X-rays to check the bone levels around your teeth." },
    ]},
    { sIdx: 5, pIdx: 6, messages: [
      { fromStudent: true,  content: "Good afternoon, Mr. Villanueva. I saw your case file — the receding gums and loose teeth need immediate attention." },
      { fromStudent: false, content: "Hello Doc Sofia. Yes, it's been getting worse. My previous dentist said I might need surgery." },
      { fromStudent: true,  content: "Let's not jump to conclusions yet. After a thorough cleaning and scaling, many cases improve significantly. Can we start there?" },
    ]},
  ];

  for (const chat of chatPairs) {
    const studentId = studentIds[chat.sIdx];
    const patientId = patientIds[chat.pIdx];
    const [p1, p2] = canonicalPair(studentId, patientId);

    const conversation = await prisma.conversation.create({
      data: { participant1Id: p1, participant2Id: p2 },
    });

    for (let i = 0; i < chat.messages.length; i++) {
      const msg = chat.messages[i];
      const senderId = msg.fromStudent ? studentId : patientId;
      const msgDate = new Date();
      msgDate.setHours(msgDate.getHours() - (chat.messages.length - i) * 2);

      await prisma.message.create({
        data: {
          conversationId: conversation.id,
          senderId,
          content: msg.content,
          isRead: i < chat.messages.length - 1,
          createdAt: msgDate,
        },
      });
    }
  }
  console.log(`✅ ${chatPairs.length} conversations with messages created`);

  // ── Print Credentials Table ──
  console.log('\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  console.log('🎉 SEED COMPLETE — All accounts use: DentaraSecure2026!');
  console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n');

  console.log('STUDENTS:');
  STUDENTS.forEach((s) => console.log(`  📧 ${s.email.padEnd(35)} ${s.fullName}`));
  console.log('\nPATIENTS:');
  PATIENTS.forEach((p) => console.log(`  📧 ${p.email.padEnd(35)} ${p.fullName}`));
  console.log('\nUNIVERSITY:');
  UNIVERSITIES.forEach((u) => console.log(`  📧 ${u.email.padEnd(35)} ${u.fullName}`));
  console.log('');
}

main()
  .catch((err) => {
    console.error('❌ Seed failed:', err);
    process.exitCode = 1;
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

'use client';

import React, { useState, useEffect } from 'react';
import {
  Menu, X, ArrowRight, PlayCircle, ScanFace, Activity, Check, GitMerge,
  BrainCircuit, ShieldCheck, LayoutDashboard, Users, Building, AlertTriangle,
  CheckCircle, ListTodo, Bot, CalendarCheck, Sparkles, Loader2, AlertCircle,
  ChevronDown, Facebook, Twitter, Instagram, Linkedin,
} from 'lucide-react';
import Footer from '@/components/custom/footer';
import {
  motion,
  AnimatePresence,
  useReducedMotion,
} from 'framer-motion';
import type { Variants } from 'framer-motion';

// ---------------------------------------------------------------------------
// Animation variant presets
// ---------------------------------------------------------------------------
const fadeUp: Variants = {
  hidden: { opacity: 0, y: 24 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: 'easeOut' as const } },
};

const staggerContainer: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.2 } },
};

const itemVariants: Variants = {
  hidden: { opacity: 0, y: 28 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: 'easeOut' as const } },
};

const floatAnimation = {
  y: [0, -15, 0],
  transition: {
    duration: 4,
    repeat: Infinity,
    ease: 'easeInOut' as const,
  },
};

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------
export default function App() {
  const shouldReduceMotion = useReducedMotion();

  // Navigation States
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [openFaqIndex, setOpenFaqIndex] = useState<number | null>(null);

  // Scroll lock effect
  useEffect(() => {
    if (isMobileMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
  }, [isMobileMenuOpen]);

  // AI Demo States
  const [symptom, setSymptom] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiResult, setAiResult] = useState<string | null>(null);
  const [aiError, setAiError] = useState<string | null>(null);

  // Waitlist States
  const [heroWaitlisted, setHeroWaitlisted] = useState(false);
  const [ctaWaitlisted, setCtaWaitlisted] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const faqs = [
    {
      q: "How does Dentara prevent patient 'ghosting'?",
      a: "Unlike informal Facebook groups, Dentara partners directly with Local Government Units (LGUs) and Barangay Health Workers. Patients are batch-scheduled and vetted by community leaders, creating social accountability that virtually eliminates no-shows on clinic day.",
    },
    {
      q: 'Is this system approved by dental universities?',
      a: 'Yes! Dentara is a B2B platform designed specifically for institutional use. Clinical coordinators have a dedicated dashboard to track student quotas, oversee matching safety, and manage liability waivers, ensuring full academic and legal compliance.',
    },
    {
      q: 'Do patients have to pay for the platform?',
      a: 'Absolutely not. Dentara is entirely free for patients. Our goal is to connect indigent communities with the free, supervised oral healthcare provided by clinical students, addressing the 92% of Filipinos with untreated decay.',
    },
    {
      q: 'How accurate is the AI Digital Triage?',
      a: 'The AI (powered by Google Gemini) acts as an initial filter, translating colloquial symptoms (Tagalog/English) into probable academic requirements. It drastically reduces obvious mismatches, though final clinical diagnosis is always verified by the student and supervising faculty in the clinic.',
    },
  ];

  const handleFaqToggle = (index: number) => {
    setOpenFaqIndex(openFaqIndex === index ? null : index);
  };

  const handleHeroWaitlist = (e: React.FormEvent) => {
    e.preventDefault();
    setHeroWaitlisted(true);
  };

  const handleCtaWaitlist = (e: React.FormEvent) => {
    e.preventDefault();
    setCtaWaitlisted(true);
  };

  const analyzeSymptoms = async () => {
    if (!symptom.trim()) {
      setAiError('Please enter a patient symptom before analyzing.');
      return;
    }
    setIsAnalyzing(true);
    setAiResult(null);
    setAiError(null);

    const apiKey = ''; // Provided by execution environment

    try {
      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [{ parts: [{ text: symptom }] }],
            systemInstruction: {
              parts: [
                {
                  text: "You are an intelligent dental triage assistant for Dentara. The user will input a patient's dental symptom or complaint, often in Tagalog. Your task is to identify the most likely simple care category that a dentistry student could help with (e.g., Tooth Filling, Tooth Removal, Tooth Replacement). Format your response strictly in two short sentences: The first sentence must state the predicted care category. The second sentence must briefly explain why based on the symptom.",
                },
              ],
            },
          }),
        }
      );

      if (!response.ok) throw new Error('Network response was not ok');

      const data = await response.json();
      const aiText =
        data.candidates?.[0]?.content?.parts?.[0]?.text ||
        'Unable to analyze symptom at this time.';
      setAiResult(aiText);
    } catch (error) {
      console.error('Gemini API Error:', error);
      setAiError('System error. Please try again later.');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="bg-[#fafcff] text-gray-800 antialiased selection:bg-[var(--color-brand-teal)] selection:text-white flex flex-col min-h-screen overflow-x-hidden font-sans">
      <style>{`
        html { scroll-behavior: smooth; }
        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: #f1f5f9; }
        ::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
        .text-gradient {
