'use server';

import { auth } from '@/auth';
import type { Prisma } from '@prisma/client';
import { prisma } from '@/lib/prisma';

type CaseRequirement = {
  name: string;
  count: number;
};

type PatientDiscoveryItem = {
  id: string;
  fullName: string;
  concern: string;
  location: string;
};

type StudentDiscoveryItem = {
  id: string;
  fullName: string;
  school: string;
  yearLevel: string;
  clinicAddress: string;
  cases: CaseRequirement[];
  availabilityJson: string | null;
};

type SearchSuccess<T> = {
  success: true;
  data: T[];
};

type SearchFailure = {
  success: false;
  error: string;
};

type SearchResponse<T> = SearchSuccess<T> | SearchFailure;

function normalize(value?: string): string {
  return value?.trim().toLowerCase() ?? '';
}

function parseCasesJson(input: unknown): CaseRequirement[] {
  if (Array.isArray(input)) {
    return input.filter(
      (item): item is CaseRequirement =>
        !!item &&
        typeof item === 'object' &&
        'name' in item &&
        'count' in item &&
        typeof (item as { name?: unknown }).name === 'string' &&
        typeof (item as { count?: unknown }).count === 'number',
    );
  }

  if (typeof input === 'string' && input.trim().length > 0) {
    try {
      const parsed = JSON.parse(input) as unknown;
      return parseCasesJson(parsed);
    } catch {
      return [];
    }
  }

  return [];
}

function tokenize(value: string): string[] {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .map((token) => token.trim())
    .filter((token) => token.length >= 3);
}

function getCaseKeywords(cases: CaseRequirement[]): string[] {
  const synonyms: Record<string, string[]> = {
    extraction: ['extract', 'removal', 'remove', 'impacted', 'wisdom'],
    endodontics: ['root', 'canal', 'pulp'],
    prosthodontics: ['crown', 'bridge', 'denture', 'prosthetic'],
    orthodontics: ['braces', 'aligner', 'malocclusion'],
    periodontics: ['gum', 'gingiva', 'periodontal'],
    cleaning: ['cleaning', 'prophylaxis', 'oral', 'hygiene'],
    restoration: ['filling', 'restoration', 'restorative'],
    surgery: ['surgery', 'surgical', 'operation'],
  };

  const keywordSet = new Set<string>();

  for (const item of cases) {
    const baseTokens = tokenize(item.name);
    for (const token of baseTokens) {
      keywordSet.add(token);
      const related = synonyms[token];
      if (related) {
        for (const synonym of related) {
          keywordSet.add(synonym);
        }
      }
    }
  }

  return Array.from(keywordSet);
}

function scoreByKeywordOverlap(text: string, keywords: string[]): number {
  if (!text || !keywords.length) {
    return 0;
  }

  const normalizedText = text.toLowerCase();
  let score = 0;

  for (const keyword of keywords) {
    if (normalizedText.includes(keyword)) {
      score += 1;
    }
  }

  return score;
}

function scoreFieldMatch(value: string, query?: string): number {
  const normalizedValue = normalize(value);
  const normalizedQuery = normalize(query);

  if (!normalizedValue || !normalizedQuery) {
    return 0;
  }

  if (normalizedValue.includes(normalizedQuery)) {
    return 3;
  }

  return tokenize(normalizedQuery).reduce((acc, token) => acc + (normalizedValue.includes(token) ? 1 : 0), 0);
}

export async function searchPatients(
  query?: string,
  locationFilter?: string,
): Promise<SearchResponse<PatientDiscoveryItem>> {
  try {
    const session = await auth();
    const normalizedQuery = normalize(query);
    const normalizedLocation = normalize(locationFilter);

    let studentNeedKeywords: string[] = [];

    if (session?.user?.id && session.user.role === 'student') {
      const studentProfile = await prisma.user.findUnique({
        where: { id: session.user.id },
        select: { casesJson: true },
      });
      studentNeedKeywords = getCaseKeywords(parseCasesJson(studentProfile?.casesJson));
    }

    const dbPatients = await prisma.user.findMany({
      where: { role: 'patient' },
      select: {
        id: true,
        fullName: true,
        concern: true,
        location: true,
      },
      orderBy: {
        createdAt: 'desc',
      },
    });

    const combined: PatientDiscoveryItem[] = dbPatients.map((patient) => ({
      id: patient.id,
      fullName: patient.fullName,
      concern: patient.concern ?? '',
      location: patient.location ?? '',
    }));

    const ranked = combined
      .map((patient, index) => ({
        patient,
        index,
        score:
          scoreByKeywordOverlap(patient.concern, studentNeedKeywords) * 4 +
          scoreFieldMatch(`${patient.fullName} ${patient.concern}`, normalizedQuery) * 2 +
          scoreFieldMatch(patient.location, normalizedLocation),
      }))
      .sort((a, b) => {
        if (b.score !== a.score) {
          return b.score - a.score;
        }
        return a.index - b.index;
      })
      .map((item) => item.patient);

    return {
      success: true,
      data: ranked,
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    return {
      success: false,
      error: `Failed to search patients: ${message}`,
    };
  }
}

export async function searchStudents(
  query?: string,
  specialtyFilter?: string,
  locationFilter?: string,
): Promise<SearchResponse<StudentDiscoveryItem>> {
  try {
    const session = await auth();
    const normalizedQuery = normalize(query);
    const normalizedSpecialty = normalize(specialtyFilter);
    const normalizedLocation = normalize(locationFilter);

    let patientNeedKeywords: string[] = [];

    if (session?.user?.id && session.user.role === 'patient') {
      const patientProfile = await prisma.user.findUnique({
        where: { id: session.user.id },
        select: { concern: true },
      });
      patientNeedKeywords = tokenize(patientProfile?.concern ?? '');
    }

    const dbStudents = await prisma.user.findMany({
      where: { role: 'student' },
      select: {
        id: true,
        fullName: true,
        school: true,
        yearLevel: true,
        clinicAddress: true,
        casesJson: true,
        availabilityJson: true,
      },
      orderBy: {
        createdAt: 'desc',
      },
    });

    const combined: StudentDiscoveryItem[] = dbStudents.map((student) => ({
      id: student.id,
      fullName: student.fullName,
      school: student.school ?? '',
      yearLevel: student.yearLevel ?? '',
      clinicAddress: student.clinicAddress ?? '',
      cases: parseCasesJson(student.casesJson),
      availabilityJson: student.availabilityJson,
    }));

    const ranked = combined
      .map((student, index) => {
        const studentKeywords = getCaseKeywords(student.cases);
        const score = patientNeedKeywords.length
          ? scoreByKeywordOverlap(studentKeywords.join(' '), patientNeedKeywords) * 4
          : 0;

        const specialtyBoost = normalizedSpecialty
          ? student.cases.some((item) => item.name && item.name.trim().length > 0 && item.name.trim().toLowerCase().includes(normalizedSpecialty)) ||
            student.cases.some((item) => item.name && item.name.trim().length > 0 && item.name.trim().toLowerCase() === normalizedSpecialty)
            ? 2
            : 0
          : 0;

        const queryBoost = scoreFieldMatch(`${student.fullName} ${student.clinicAddress}`, normalizedQuery) * 2;
        const locationBoost = scoreFieldMatch(student.clinicAddress, normalizedLocation);

        return {
          student,
          index,
          score: score + specialtyBoost + queryBoost + locationBoost,
        };
      })
      .sort((a, b) => {
        if (b.score !== a.score) {
          return b.score - a.score;
        }
        return a.index - b.index;
      })
      .map((item) => item.student);

    return {
      success: true,
      data: ranked,
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    return {
      success: false,
      error: `Failed to search students: ${message}`,
    };
  }
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import bcrypt from "bcryptjs";

export async function GET(request: NextRequest) {
  try {
    // 1. Security Gate: Verify the secret key from the URL
    const { searchParams } = new URL(request.url);
    const providedSecret = searchParams.get("secret");
    const requiredSecret = process.env.UNIVERSITY_SEED_SECRET;

    if (!requiredSecret || providedSecret !== requiredSecret) {
      return NextResponse.json(
        { error: "Unauthorized. Invalid or missing seed secret." }, 
        { status: 401 }
      );
    }

    const email = "admin@university.edu";
    // 2. Pull the password securely from the .env file
    const password = process.env.UNIVERSITY_ADMIN_PASSWORD;

    if (!password) {
      return NextResponse.json(
        { error: "Server Configuration Error: Missing Admin Password in .env" }, 
        { status: 500 }
      );
    }

    // 3. Check for existing account
    const existing = await prisma.user.findUnique({ where: { email } });
    if (existing) {
      return NextResponse.json({ message: "University account is already provisioned." });
    }

    // 4. Hash and Inject
    const hashedPassword = await bcrypt.hash(password, 12);

    await prisma.user.create({
      data: {
        email: email,
        password: hashedPassword,
        fullName: "UP College of Dentistry",
        role: "university",
      },
    });

    return NextResponse.json({ 
      success: true, 
      message: "University provisioned successfully. You may now log in.",
      email: email
      // Notice we do NOT return the password in the JSON response for security
    });
  } catch (error) {
    return NextResponse.json({ error: "Injection failed" }, { status: 500 });
  }
}

'use client';

import React, { useEffect, useRef, useState } from 'react';
import { useRouter } from 'next/navigation';
import { ArrowLeft, ImageIcon, MoreVertical, Paperclip, Phone, Send } from 'lucide-react';
import { sendMessage, markConversationAsReadAction } from '@/app/actions/chat';
import { getSupabaseBrowserClient } from '@/lib/supabase-browser';
import type { ChatMessageItem, ChatConversationItem } from '@/lib/chat-server';

type Props = {
  currentUserId: string;
  conversationId: string;
  initialMessages: ChatMessageItem[];
  otherUser: {
    fullName: string;
    image: string | null;
  };
  basePath: string;
};

function initials(name: string) {
  return name
    .split(' ')
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? '')
    .join('');
}

function formatShortTime(iso: string) {
  return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export default function ChatActiveClient({ currentUserId, conversationId, initialMessages, otherUser, basePath }: Props) {
  const router = useRouter();
  const [messages, setMessages] = useState<ChatMessageItem[]>(initialMessages);
  const [messageInput, setMessageInput] = useState('');
  const [sending, setSending] = useState(false);
  const bottomRef = useRef<HTMLDivElement | null>(null);

  // Auto-Scroll to bottom
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Real-time subscription
  useEffect(() => {
    const supabase = getSupabaseBrowserClient();

    if (!supabase) return;

    const channel = supabase
      .channel(`conversation-${conversationId}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'Message',
          filter: `conversationId=eq.${conversationId}`,
        },
        async (payload) => {
          const incoming = payload.new as ChatMessageItem;

          setMessages((prev) => {
            if (prev.some((msg) => msg.id === incoming.id)) {
              return prev;
            }
            return [...prev, incoming];
          });

          if (incoming.senderId !== currentUserId) {
            await markConversationAsReadAction(conversationId);
          }
        },
      )
      .subscribe();

    return () => {
      channel.unsubscribe();
    };
  }, [conversationId, currentUserId]);

  async function onSend() {
    if (sending) return;

    const content = messageInput.trim();
    if (!content) return;

    setSending(true);

    try {
      const sent = await sendMessage(conversationId, content);
      setMessageInput('');

      setMessages((prev) => {
        if (prev.some((msg) => msg.id === sent.id)) {
          return prev;
        }
        return [...prev, sent as ChatMessageItem];
      });
    } finally {
      setSending(false);
    }
  }

  return (
    <div className="flex flex-col h-[100svh] bg-slate-50">
      {/* Header */}
      <header className="bg-white px-4 py-3 border-b border-gray-100 flex items-center justify-between shadow-sm shrink-0">
        <div className="flex items-center gap-3">
          <button
            onClick={() => router.push(`${basePath}/chats`)}
            className="p-2 -ml-2 rounded-full hover:bg-slate-50 text-gray-500 transition-colors"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>

          <div className="relative">
            <div className="h-10 w-10 rounded-full bg-brand-teal/10 text-brand-teal flex items-center justify-center font-bold text-sm">
              {initials(otherUser.fullName)}
            </div>
          </div>

          <div className="flex flex-col">
            <h2 className="text-sm font-bold text-slate-900">{otherUser.fullName}</h2>
            <span className="text-[11px] text-emerald-500 font-medium">Online</span>
          </div>
        </div>

        <div className="flex items-center gap-1">
          <button className="p-2 rounded-full hover:bg-slate-50 text-gray-500 transition-colors">
            <Phone className="h-5 w-5" />
          </button>
          <button className="p-2 rounded-full hover:bg-slate-50 text-gray-500 transition-colors">
            <MoreVertical className="h-5 w-5" />
          </button>
        </div>
      </header>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((message) => {
          const mine = message.senderId === currentUserId;

          return (
            <div key={message.id} className={`flex flex-col ${mine ? 'items-end' : 'items-start'}`}>
              <div
                className={`max-w-[75%] px-4 py-2.5 shadow-sm text-sm ${
                  mine
                    ? 'bg-brand-teal text-white rounded-2xl rounded-br-sm'
                    : 'bg-white text-gray-800 border border-gray-50 rounded-2xl rounded-bl-sm'
                }`}
              >
                <p className="whitespace-pre-wrap break-words">{message.content}</p>
              </div>
              <span className={`text-[10px] mt-1 px-1 font-medium ${mine ? 'text-gray-400' : 'text-gray-400'}`}>
                {formatShortTime(message.createdAt)}
              </span>
            </div>
          );
        })}
        <div ref={bottomRef} className="h-1" />
      </div>

      {/* Input Bar */}
      <div className="p-4 bg-transparent shrink-0">
        <div className="flex items-center gap-2 bg-white rounded-full p-2 border border-gray-200 shadow-sm">
          <button className="p-2 text-gray-400 hover:text-gray-600 hover:bg-slate-50 rounded-full transition-colors">
            <Paperclip className="h-5 w-5" />
          </button>
          <button className="p-2 text-gray-400 hover:text-gray-600 hover:bg-slate-50 rounded-full transition-colors">
            <ImageIcon className="h-5 w-5" />
          </button>

          <input
            type="text"
            value={messageInput}
            onChange={(e) => setMessageInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                void onSend();
              }
            }}
            placeholder="Type a message..."
            className="flex-1 bg-transparent px-2 py-2 text-sm text-gray-800 placeholder:text-gray-400 focus:outline-none"
          />

          <button
            onClick={() => void onSend()}
            disabled={sending || !messageInput.trim()}
            className="h-10 w-10 bg-brand-teal text-white rounded-full flex items-center justify-center hover:opacity-90 transition-opacity disabled:opacity-50 disabled:cursor-not-allowed shrink-0"
          >
            <Send className="h-4 w-4 ml-0.5" />
          </button>
        </div>
      </div>
    </div>
  );
}

