'use client';

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import type { Variants } from 'framer-motion';
import { User, Mail, Phone, MapPin, Bell, Shield, CreditCard, HelpCircle, ChevronRight, Camera, Star, Calendar, LogOut, Loader2, Edit2, Check, X, Stethoscope } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { signOut } from 'next-auth/react';
import SignOutConfirmDialog from '@/components/custom/SignOutConfirmDialog';
import { useRole } from '@/lib/role-context';
import { getCurrentUserProfile } from '@/app/actions/user';

const ANIM: Variants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 200, damping: 24, staggerChildren: 0.1 } }
};
const ITEM: Variants = {
  hidden: { opacity: 0, y: 15 },
  visible: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 24 } }
};

interface Props {
  user: { id?: string; fullName: string; role: string; location?: string | null };
}

export default function PatientProfileClient({ user: initialUser }: Props) {
  const router = useRouter();
  const { user: authUser } = useRole();
  const [showSignOutConfirm, setShowSignOutConfirm] = useState(false);
  const [isSigningOut, setIsSigningOut] = useState(false);

  const [mounted, setMounted] = useState(false);
  type UserProfile = Awaited<ReturnType<typeof getCurrentUserProfile>>;
  const [profile, setProfile] = useState<UserProfile>(null);
  const [loading, setLoading] = useState(true);
  const [isEditing, setIsEditing] = useState(false);

  const [formData, setFormData] = useState({
    fullName: '',
    age: '',
    phone: '',
    location: '',
    concern: '',
  });

  useEffect(() => {
    setMounted(true);
    async function loadData() {
      if (!authUser?.id) return;
      const data = await getCurrentUserProfile();
      setProfile(data);
      setFormData({
        fullName: data?.fullName || '',
        age: data?.age?.toString() || '',
        phone: data?.phone || '',
        location: data?.location || '',
        concern: data?.concern || '',
      });
      setLoading(false);
    }
    loadData();
  }, [authUser?.id]);

  const handleConfirmSignOut = React.useCallback(async () => {
    try {
      setIsSigningOut(true);
      await signOut({ callbackUrl: '/app/login' });
    } catch {
      setIsSigningOut(false);
      setShowSignOutConfirm(false);
      router.push('/app/login');
    }
  }, [router]);

  if (!mounted) return null;

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[50vh] space-y-4">
        <Loader2 className="h-8 w-8 animate-spin text-brand-teal" />
        <p className="text-sm text-muted-foreground font-medium animate-pulse">Loading profile...</p>
      </div>
    );
  }

  const displayName = profile?.fullName || initialUser.fullName;
  const location = profile?.location || 'Update your location';
  
  const handleSave = async () => {
    // Optional: Add server action call to save profile
    setIsEditing(false);
    setProfile((prev) => prev ? { ...prev, ...formData, age: formData.age ? parseInt(formData.age, 10) : prev.age } : prev);
  };

  return (
    <motion.div variants={ANIM} initial="hidden" animate="visible" className="space-y-6">
      {/* Profile Header */}
      <motion.div variants={ITEM} className="glass-card-solid p-6 text-center">
        <div className="relative w-20 h-20 mx-auto mb-3">
          <div className="w-20 h-20 rounded-3xl bg-brand-teal/10 flex items-center justify-center text-brand-teal font-bold text-2xl">
            {displayName.split(' ').map((n: string) => n[0]).join('').slice(0, 2)}
          </div>
          <button className="absolute -bottom-1 -right-1 w-7 h-7 rounded-xl bg-brand-teal text-white flex items-center justify-center shadow-lg hover:scale-105 transition-transform">
            <Camera className="h-3.5 w-3.5" />
          </button>
        </div>
        <h3 className="text-lg font-bold text-foreground">{displayName}</h3>
        <p className="text-xs text-muted-foreground mt-0.5">{location}</p>
        <div className="flex flex-wrap items-center justify-center gap-x-4 gap-y-2 mt-3 text-xs text-muted-foreground">
          <span className="flex items-center gap-1 shrink-0"><Calendar className="h-3 w-3" /> New Patient</span>
          <span className="flex items-center gap-1 shrink-0"><Star className="h-3 w-3 text-amber-400" /> Unrated</span>
        </div>
      </motion.div>

      {/* Personal Info */}
      <motion.div variants={ITEM}>
        <div className="flex items-center justify-between mb-3">
          <h3 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Personal Information</h3>
          {!isEditing ? (
            <button onClick={() => setIsEditing(true)} className="text-xs text-brand-teal font-medium flex items-center gap-1">
              <Edit2 className="h-3 w-3" /> Edit
            </button>
          ) : (
            <div className="flex items-center gap-2">
              <button onClick={() => setIsEditing(false)} className="text-xs text-muted-foreground font-medium flex items-center gap-1">
                <X className="h-3 w-3" /> Cancel
              </button>
              <button onClick={handleSave} className="text-xs text-brand-teal font-medium flex items-center gap-1">
                <Check className="h-3 w-3" /> Save
              </button>
            </div>
          )}
        </div>
        <div className="glass-card-solid divide-y divide-gray-100/30">
          {[
            { id: 'fullName', icon: User, label: "Full Name", value: profile?.fullName },
            { id: 'age', icon: User, label: "Age", value: profile?.age?.toString() },
            { id: 'email', icon: Mail, label: "Email", value: profile?.email || 'Not provided', readOnly: true },
            { id: 'phone', icon: Phone, label: "Phone", value: profile?.phone || '' },
            { id: 'location', icon: MapPin, label: "Location", value: profile?.location || '' },
            { id: 'concern', icon: Stethoscope, label: "Primary Concern", value: profile?.concern || '' },
          ].map((item, i) => (
            <div key={i} className="flex items-center gap-3 p-4">
              <div className="w-9 h-9 rounded-xl bg-brand-teal/10 flex items-center justify-center shrink-0">
                <item.icon className="h-4 w-4 text-brand-teal" />
              </div>
              <div className="flex-1">
                <p className="text-[10px] text-muted-foreground">{item.label}</p>
                {isEditing && !item.readOnly ? (
                  <input
                    type={item.id === 'age' ? 'number' : 'text'}
                    value={formData[item.id as keyof typeof formData] || ''}
                    onChange={(e) => setFormData({ ...formData, [item.id]: e.target.value })}
                    className="w-full bg-transparent border-b border-brand-teal/30 focus:border-brand-teal outline-none text-sm font-medium text-foreground pb-1"
                    placeholder={`Enter ${item.label.toLowerCase()}`}
                  />
                ) : (
                  <p className="text-sm font-medium text-foreground">{item.value || <span className="text-gray-400 italic">Not set</span>}</p>
                )}
              </div>
              {!isEditing && <ChevronRight className="h-4 w-4 text-muted-foreground" />}
            </div>
          ))}
        </div>
      </motion.div>

      {/* Settings */}
      <motion.div variants={ITEM}>
        <h3 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3">Settings</h3>
        <div className="glass-card-solid divide-y divide-gray-100/30">
          {[
            { icon: Bell, label: "Notifications", desc: "Manage alerts & reminders" },
            { icon: Shield, label: "Privacy & Security", desc: "Password, 2FA, data" },
            { icon: CreditCard, label: "Payment Methods", desc: "Cards & billing history" },
            { icon: HelpCircle, label: "Help & Support", desc: "FAQs, contact us" },
          ].map((item, i) => (
            <button key={i} className="w-full flex items-center gap-3 p-4 hover:bg-gray-50/30 transition-colors text-left">
              <div className="w-9 h-9 rounded-xl bg-gray-100/50 flex items-center justify-center shrink-0">
                <item.icon className="h-4 w-4 text-muted-foreground" />
              </div>
              <div className="flex-1">
                <p className="text-sm font-medium text-foreground">{item.label}</p>
                <p className="text-[10px] text-muted-foreground">{item.desc}</p>
              </div>
              <ChevronRight className="h-4 w-4 text-muted-foreground" />
            </button>
          ))}
        </div>
      </motion.div>

      {/* Logout */}
      <motion.div variants={ITEM}>
        <button
          onClick={() => setShowSignOutConfirm(true)}
          className="w-full glass-card-solid p-4 flex items-center gap-3 hover:bg-red-50/50 transition-colors"
        >
          <div className="w-9 h-9 rounded-xl bg-red-50 flex items-center justify-center shrink-0">
            <LogOut className="h-4 w-4 text-red-500" />
          </div>
          <span className="text-sm font-semibold text-red-500">Sign Out</span>
        </button>
      </motion.div>

      <SignOutConfirmDialog
        open={showSignOutConfirm}
        onStay={() => setShowSignOutConfirm(false)}
        onExit={handleConfirmSignOut}
        isSubmitting={isSigningOut}
      />
    </motion.div>
  );
}

'use client';

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import type { Variants } from 'framer-motion';
import { Calendar, Clock, CheckCircle2, XCircle, MapPin } from 'lucide-react';
import { BookingStatus } from '@prisma/client';
import { completeBookingAction } from '@/app/actions/booking';
import { useRouter } from 'next/navigation';

const ANIM: Variants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 200, damping: 24, staggerChildren: 0.1 } }
};
const ITEM: Variants = {
  hidden: { opacity: 0, y: 15 },
  visible: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 24 } }
};

type StudentBookingItem = {
  id: string;
  status: BookingStatus;
  scheduledAt: string;
  notes: string | null;
  caseLabel: string | null;
  patientName: string;
  clinicAddress: string | null;
};

type StudentBookingsClientProps = {
  bookings: StudentBookingItem[];
};

const statusConfig: Record<string, { label: string; color: string }> = {
  PENDING: { label: 'Pending', color: 'bg-amber-50 text-amber-700 border-amber-200/60 dark:bg-amber-500/10 dark:border-amber-500/20' },
  CONFIRMED: { label: 'Confirmed', color: 'bg-emerald-50 text-emerald-700 border-emerald-200/60 dark:bg-emerald-500/10 dark:border-emerald-500/20' },
  CANCELLED: { label: 'Cancelled', color: 'bg-red-50 text-red-600 border-red-200/60 dark:bg-red-500/10 dark:border-red-500/20' },
  COMPLETED: { label: 'Completed', color: 'bg-blue-50 text-blue-700 border-blue-200/60 dark:bg-blue-500/10 dark:border-blue-500/20' },
};

function formatDateLabel(iso: string): string {
  return new Date(iso).toLocaleDateString([], {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

function formatTimeLabel(iso: string): string {
  return new Date(iso).toLocaleTimeString([], {
    hour: '2-digit',
    minute: '2-digit',
  });
}

function isUpcoming(status: BookingStatus, scheduledAtIso: string): boolean {
  const s = status as string;
  if (s === 'CANCELLED' || s === 'COMPLETED') return false;
  return new Date(scheduledAtIso).getTime() >= Date.now();
}

export default function StudentBookingsClient({ bookings }: StudentBookingsClientProps) {
  const [tab, setTab] = useState<"upcoming" | "past">("upcoming");
  const [loadingId, setLoadingId] = useState<string | null>(null);
  const [optimisticStatuses, setOptimisticStatuses] = useState<Record<string, BookingStatus>>({});
  const [mounted, setMounted] = useState(false);
  const router = useRouter();

  React.useEffect(() => {
    setMounted(true);
  }, []);

  async function handleComplete(id: string) {
    setOptimisticStatuses(prev => ({ ...prev, [id]: 'COMPLETED' as BookingStatus }));
    try {
      await completeBookingAction(id);
      
      // Delay refresh slightly so the user can enjoy the luxurious transition
      setTimeout(() => {
        router.refresh();
      }, 1000);
    } catch (err) {
      setOptimisticStatuses(prev => {
        const next = { ...prev };
        delete next[id];
        return next;
      });
      alert(err instanceof Error ? err.message : 'Failed to complete booking');
    }
  }

  const upcomingCount = bookings.filter((booking) => isUpcoming(booking.status, booking.scheduledAt)).length;
  const confirmedCount = bookings.filter((booking) => (booking.status as string) === 'CONFIRMED').length;
  const completedCount = bookings.filter((booking) => (booking.status as string) === 'COMPLETED').length;
  const cancelledCount = bookings.filter((booking) => (booking.status as string) === 'CANCELLED').length;

  const filteredBookings = bookings.filter((booking) =>
    tab === 'upcoming' ? isUpcoming(booking.status, booking.scheduledAt) : !isUpcoming(booking.status, booking.scheduledAt),
  );

  return (
    <motion.div variants={ANIM} initial="hidden" animate="visible" className="space-y-6">
      <motion.div variants={ITEM} className="pt-2">
        <h2 className="text-2xl font-bold tracking-tight text-foreground">My Bookings</h2>
        <p className="text-muted-foreground text-sm mt-1">Your clinical schedule</p>
      </motion.div>

      <motion.div variants={ITEM} className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {[
          { label: 'Upcoming', value: String(upcomingCount), icon: Clock },
          { label: 'Confirmed', value: String(confirmedCount), icon: CheckCircle2 },
          { label: 'Completed', value: String(completedCount), icon: CheckCircle2 },
          { label: 'Cancelled', value: String(cancelledCount), icon: XCircle },
        ].map((stat, i) => (
          <div key={i} className="glass-card-solid p-3 sm:p-4 text-center">
            <stat.icon className="h-4 w-4 text-brand-teal mx-auto mb-1.5" />
            <p className="text-xl font-bold text-foreground">{stat.value}</p>
            <p className="text-[10px] text-muted-foreground font-medium">{stat.label}</p>
          </div>
        ))}
      </motion.div>

      <motion.div variants={ITEM} className="flex gap-1 bg-gray-100/50 p-1 rounded-2xl">
        {(["upcoming", "past"] as const).map((t) => (
          <button
            key={t}
            onClick={() => setTab(t)}
            className={`flex-1 py-2.5 rounded-xl text-xs font-semibold transition-all duration-200 ${
              tab === t ? "bg-white text-foreground shadow-sm" : "text-muted-foreground"
            }`}
          >
            {t === "upcoming" ? "Upcoming" : "Past"}
          </button>
        ))}
      </motion.div>

      <motion.div variants={ITEM} className="space-y-3">
        {!filteredBookings.length ? (
          <div className="glass-card-solid p-4">
            <p className="text-sm font-medium text-muted-foreground">
              {tab === 'upcoming' ? 'No upcoming bookings yet.' : 'No past bookings yet.'}
            </p>
          </div>
        ) : (
          <AnimatePresence mode="popLayout">
            {filteredBookings.map((booking) => {
              const currentStatus = (optimisticStatuses[booking.id] || booking.status) as string;
              const sc = statusConfig[currentStatus] || statusConfig['PENDING'];

              return (
                <motion.div 
                  layout
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.95, filter: 'blur(4px)', transition: { duration: 0.3 } }}
                  key={booking.id} 
                  className="glass-card-solid p-4 hover-lift cursor-pointer relative group"
                >
                  <div className="flex items-start justify-between mb-3">
                    <div>
                      <h4 className="font-semibold text-foreground text-sm">{booking.patientName}</h4>
                      <p className="text-[11px] text-muted-foreground mt-1">
                        Case: {booking.caseLabel || 'General Care'}
                      </p>

                    </div>
                    <div className="flex flex-col items-end gap-2">
                      <motion.span 
                        layout
                        initial={{ opacity: 0.5 }}
                        animate={{ opacity: 1 }}
                        className={`text-[10px] font-semibold px-2.5 py-1 rounded-full border shadow-sm transition-colors duration-500 ${sc.color}`}
                      >
                        {sc.label}
                      </motion.span>
                      
                      <AnimatePresence>
                        {currentStatus === 'CONFIRMED' && (
                          <motion.button
                            layout
                            initial={{ opacity: 0, height: 0, y: -10 }}
                            animate={{ opacity: 1, height: 'auto', y: 0 }}
                            exit={{ opacity: 0, height: 0, scale: 0.8, filter: 'blur(2px)' }}
                            onClick={(e) => {
                              e.stopPropagation();
                              handleComplete(booking.id);
                            }}
                            disabled={loadingId === booking.id}
                            className="py-1 px-3 bg-white shadow-[0_2px_10px_var(--color-brand-teal)] dark:bg-black/20 text-brand-teal hover:bg-brand-teal hover:text-white text-[10px] font-bold rounded-full transition-all duration-300 border border-brand-teal/20 flex items-center gap-1.5 disabled:opacity-50 hover:shadow-[0_4px_12px_var(--color-brand-teal)] whitespace-nowrap overflow-hidden"
                          >
                            {loadingId === booking.id ? (
                              <Clock className="h-3 w-3 animate-spin" />
                            ) : (
                              <CheckCircle2 className="h-3 w-3" />
                            )}
                            <span>{loadingId === booking.id ? 'Updating...' : 'Complete'}</span>
                          </motion.button>
                        )}
                      </AnimatePresence>
                    </div>
                  </div>
                  <div className="flex items-center gap-4 text-xs text-muted-foreground">
                  <span className="flex items-center gap-1"><Calendar className="h-3 w-3" />{mounted ? formatDateLabel(booking.scheduledAt) : '...'}</span>
                    <span className="flex items-center gap-1"><Clock className="h-3 w-3" />{mounted ? formatTimeLabel(booking.scheduledAt) : '...'}</span>
                    <span className="flex items-center gap-1"><MapPin className="h-3 w-3" />{booking.clinicAddress || 'Clinic location not available'}</span>
                  </div>
                  {booking.notes ? <p className="mt-2 text-xs text-muted-foreground">Notes: {booking.notes}</p> : null}
                </motion.div>
              );
            })}
          </AnimatePresence>
        )}
      </motion.div>
    </motion.div>
  );
}

